mapper.select:
SELECT COUNT(*)
FROM risk_event re
WHERE re.supplier_id = #{supplierId}

SELECT re.id, re.supplier_id, s.name AS supplier_name, re.risk_dimension, re.description, re.status, re.triggered_at, COALESCE(re.closed_at, re.triggered_at) AS updated_at, re.source_url, re.close_note FROM risk_event re INNER JOIN supplier s ON s.id = re.supplier_id
AND re.status = #{query.status}
AND re.risk_dimension = #{query.riskDimension}
AND re.description ILIKE '%' || #{query.keyword} || '%'
ORDER BY re.triggered_at DESC LIMIT #{query.pageSize} OFFSET #{query.offset}

SELECT COUNT(*)
FROM risk_event re
INNER JOIN supplier s ON s.id = re.supplier_id


        AND re.status = #{query.status}


        AND re.risk_dimension = #{query.riskDimension}


